/**
 * E2E Test: Accessibility & Responsiveness
 * Verifica acessibilidade básica (ARIA, keyboard navigation, contrast)
 * e responsividade em viewports mobile/desktop.
 */

import { test, expect } from '@playwright/test';

test.describe('Accessibility Basics', () => {
  test('Home page has skip-to-content or main landmark', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    // Check for main landmark
    const main = page.locator('main, [role="main"]');
    const hasMain = (await main.count()) > 0;

    // Check for skip link
    const skipLink = page.locator('a[href="#main"], a[href="#content"], a:has-text("Pular"), a:has-text("Skip")');
    const hasSkip = (await skipLink.count()) > 0;

    // At least main landmark should exist
    expect(hasMain || hasSkip).toBeTruthy();
  });

  test('Images have alt attributes', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    const images = page.locator('img');
    const imgCount = await images.count();

    // Check that all images have alt text (allow empty alt for decorative)
    let missingAlt = 0;
    for (let i = 0; i < Math.min(imgCount, 20); i++) {
      const alt = await images.nth(i).getAttribute('alt');
      if (alt === null) missingAlt++;
    }

    // At most 30% can be missing alt — generous threshold for decorative images
    if (imgCount > 0) {
      expect(missingAlt / imgCount).toBeLessThan(0.5);
    }
  });

  test('Buttons and links are focusable', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    // Tab through the page and verify focus moves
    await page.keyboard.press('Tab');
    const focusedElement = await page.evaluate(() => {
      const el = document.activeElement;
      return el ? el.tagName.toLowerCase() : null;
    });

    // Something should be focused after Tab
    expect(focusedElement).toBeTruthy();
  });

  test('No auto-playing audio or video', async ({ page }) => {
    await page.goto('/', { waitUntil: 'domcontentloaded' });

    const autoplayMedia = page.locator('audio[autoplay], video[autoplay]');
    const count = await autoplayMedia.count();

    // Auto-playing media is an accessibility issue
    expect(count).toBe(0);
  });
});

test.describe('Responsive Design', () => {
  test('Home page renders on mobile viewport', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 812 }); // iPhone X
    const response = await page.goto('/', { waitUntil: 'domcontentloaded' });
    expect(response!.status()).toBeLessThan(500);

    // Page should not have horizontal overflow causing issues
    const bodyWidth = await page.evaluate(() => document.body.scrollWidth);
    const viewportWidth = await page.evaluate(() => window.innerWidth);
    // Allow some small overflow (scrollbar, etc.) but not massive
    expect(bodyWidth).toBeLessThan(viewportWidth * 1.5);
  });

  test('Home page renders on tablet viewport', async ({ page }) => {
    await page.setViewportSize({ width: 768, height: 1024 }); // iPad
    const response = await page.goto('/', { waitUntil: 'domcontentloaded' });
    expect(response!.status()).toBeLessThan(500);
  });

  test('Home page renders on desktop viewport', async ({ page }) => {
    await page.setViewportSize({ width: 1920, height: 1080 });
    const response = await page.goto('/', { waitUntil: 'domcontentloaded' });
    expect(response!.status()).toBeLessThan(500);
  });

  test('Login page is usable on mobile', async ({ page }) => {
    await page.setViewportSize({ width: 375, height: 812 });
    await page.goto('/login', { waitUntil: 'domcontentloaded' });

    // Inputs should be visible and not clipped
    const emailInput = page.locator(
      'input[type="email"], input[name="email"], input[placeholder*="email" i]'
    );
    const count = await emailInput.count();
    if (count > 0) {
      await expect(emailInput.first()).toBeVisible();
    }
  });
});

test.describe('Dark Mode Support', () => {
  test('Page respects prefers-color-scheme: dark', async ({ page }) => {
    // Emulate dark mode
    await page.emulateMedia({ colorScheme: 'dark' });
    const response = await page.goto('/', { waitUntil: 'domcontentloaded' });
    expect(response!.status()).toBeLessThan(500);

    // Page should not crash in dark mode
    const bodyBg = await page.evaluate(() => {
      return window.getComputedStyle(document.body).backgroundColor;
    });
    expect(bodyBg).toBeTruthy();
  });
});
